#[derive(Debug, Clone)]
enum ScoreUpdate {
    ScoreChanged { team_a: String, score_a: i32, team_b: String, score_b: i32 },
    PlayerSubstituted { player_name: String, game_id: u64 },
    GameOver { final_score_a: i32, final_score_b: i32 },
}

