use std::collections::VecDeque;

#[derive(Debug)]
enum MovementCommand {
    MoveTo { x: i32, y: i32 },
    WaitFor { duration_ticks: u64 },
    AttackTarget { target_id: u32 },
}

struct UnitPathfinderServer {
    command_queue: VecDeque<MovementCommand>,
}

impl UnitPathfinderServer {
    fn new() -> Self {
        UnitPathfinderServer {
            command_queue: VecDeque::new(),
        }
    }

    fn enqueue_command(&mut self, command: MovementCommand) {
        self.command_queue.push_back(command);
    }

    fn process_next_tick(&mut self) -> Option<String> {
        if let Some(command) = self.command_queue.pop_front() {
            match command {
                MovementCommand::MoveTo { x, y } => {
                    Some(format!("Processing Move: Unit needs to calculate path to ({}, {}).", x, y))
                }
                MovementCommand::WaitFor { duration_ticks } => {
                    Some(format!("Processing Wait: Unit will pause for {} ticks.", duration_ticks))
                }
                MovementCommand::AttackTarget { target_id } => {
                    Some(format!("Processing Attack: Unit locks onto enemy ID {}.", target_id))
                }
            }
        } else {
            None
        }
    }
}

fn main() {
    let mut server = UnitPathfinderServer::new();
    server.enqueue_command(MovementCommand::MoveTo { x: 10, y: 5 });
    server.enqueue_command(MovementCommand::WaitFor { duration_ticks: 60 });
    server.enqueue_command(MovementCommand::AttackTarget { target_id: 42 });

    println!("--- Ticks Start ---n");
