    }
}

use std::fmt::{self, Display};

#[derive(Debug)]
enum DeviceState {
    Disconnected,
    Connecting(u32),
    Authenticating,
    Success(String),
    Error(String),
}

impl Display for DeviceState {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            DeviceState::Disconnected => write!(f, "Offline"),
            DeviceState::Connecting(attempt) => write!(f, "Connecting (Attempt {})", attempt),
            DeviceState::Authenticating => write!(f, "Waiting for User Input..."),
            DeviceState::Success(key) => write!(f, "Authenticated with key: {}", key),
            DeviceState::Error(msg) => write!(f, "Failed to connect: {}", msg),
        }
    }
}

fn simulate_connection_flow() -> DeviceState {
    let initial_state = DeviceState::Disconnected;
    println!("Initial State: {}", initial_state);

    let state1 = DeviceState::Connecting(1);
    println!("State after first attempt: {}", state1);

    let state2 = DeviceState::Authenticating;
    println!("Current Process State: {}", state2);

    let final_state = DeviceState::Success("Secure Element ID 0xDEADBEEF".to_string());
    println!("Final State: {}", final_state);

    final_state
}

fn main() {
    simulate_connection_flow();
}

