use std::io::{self, Write};

#[derive(Debug)]
enum NetworkMessage {
    Text(String),
    Binary(Vec<u8>),
    Status(i32),
}

fn process_message(msg: NetworkMessage) -> io::Result<()> {
    match msg {
        NetworkMessage::Text(text) => {
            println!("Received text content: {}", text);
            Ok(())
        }
        NetworkMessage::Binary(bytes) => {
            let size = bytes.len();
            if size > 0 {
                print!(".");
                io::stdout().flush()?;
            } else {
                println!("Got empty binary packet.");
            }
            Ok(())
        }
        NetworkMessage::Status(code) => {
            match code {
                200 => println!("Successfully connected."),
                403 => println!("Access forbidden."),
                _ => println!("Unknown status code received: {}", code),
            }
            Ok(())
        }
    }
}

fn main() -> io::Result<()> {
    let messages = vec![
        NetworkMessage::Text("Hello world from the client".to_string()),
        NetworkMessage::Status(200),
        NetworkMessage::Binary(b"Some data chunk".to_vec()),
        NetworkMessage::Text("Done".to_string()),
    ];

    for message in messages {
        println!("
--- Processing ---");
        process_message(message)?;
    }
    Ok(())
}
